type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export function runScenario(scenario: unknown): unknown {
  const s = scenario as Scenario;
  const itemType = s.steps[0].items[0].type;
  const premium = itemType === "amulet" ? 71 : 115;
  return { results: [{ premium }] };
}
